// Then sets up TwoFAVerifier.Verify return parameters for the expectation previously defined by the When method
func (e *TwoFAVerifierMockVerifyExpectation) Then(b1 bool, err error) *TwoFAVerifierMock {
	e.results = &TwoFAVerifierMockVerifyResults{b1, err}
	return e.mock
}

// Times sets number of times TwoFAVerifier.Verify should be invoked
func (mmVerify *mTwoFAVerifierMockVerify) Times(n uint64) *mTwoFAVerifierMockVerify {
	if n == 0 {
		mmVerify.mock.t.Fatalf("Times of TwoFAVerifierMock.Verify mock can not be zero")
	}
	mm_atomic.StoreUint64(&mmVerify.expectedInvocations, n)
	mmVerify.expectedInvocationsOrigin = minimock.CallerInfo(1)
	return mmVerify
}

func (mmVerify *mTwoFAVerifierMockVerify) invocationsDone() bool {
	if len(mmVerify.expectations) == 0 && mmVerify.defaultExpectation == nil && mmVerify.mock.funcVerify == nil {
		return true
	}

	totalInvocations := mm_atomic.LoadUint64(&mmVerify.mock.afterVerifyCounter)
	expectedInvocations := mm_atomic.LoadUint64(&mmVerify.expectedInvocations)

	return totalInvocations > 0 && (expectedInvocations == 0 || expectedInvocations == totalInvocations)
}

// Verify implements mm_auth.TwoFAVerifier
func (mmVerify *TwoFAVerifierMock) Verify(ctx context.Context, userID string, code string) (b1 bool, err error) {
	mm_atomic.AddUint64(&mmVerify.beforeVerifyCounter, 1)
	defer mm_atomic.AddUint64(&mmVerify.afterVerifyCounter, 1)

	mmVerify.t.Helper()

	if mmVerify.inspectFuncVerify != nil {
		mmVerify.inspectFuncVerify(ctx, userID, code)
	}

	mm_params := TwoFAVerifierMockVerifyParams{ctx, userID, code}

	// Record call args
	mmVerify.VerifyMock.mutex.Lock()
	mmVerify.VerifyMock.callArgs = append(mmVerify.VerifyMock.callArgs, &mm_params)
	mmVerify.VerifyMock.mutex.Unlock()

	for _, e := range mmVerify.VerifyMock.expectations {
		if minimock.Equal(*e.params, mm_params) {
			mm_atomic.AddUint64(&e.Counter, 1)
			return e.results.b1, e.results.err
		}
	}

	if mmVerify.VerifyMock.defaultExpectation != nil {
		mm_atomic.AddUint64(&mmVerify.VerifyMock.defaultExpectation.Counter, 1)
		mm_want := mmVerify.VerifyMock.defaultExpectation.params
		mm_want_ptrs := mmVerify.VerifyMock.defaultExpectation.paramPtrs

		mm_got := TwoFAVerifierMockVerifyParams{ctx, userID, code}

		if mm_want_ptrs != nil {

			if mm_want_ptrs.ctx != nil && !minimock.Equal(*mm_want_ptrs.ctx, mm_got.ctx) {
				mmVerify.t.Errorf("TwoFAVerifierMock.Verify got unexpected parameter ctx, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmVerify.VerifyMock.defaultExpectation.expectationOrigins.originCtx, *mm_want_ptrs.ctx, mm_got.ctx, minimock.Diff(*mm_want_ptrs.ctx, mm_got.ctx))
			}

			if mm_want_ptrs.userID != nil && !minimock.Equal(*mm_want_ptrs.userID, mm_got.userID) {
				mmVerify.t.Errorf("TwoFAVerifierMock.Verify got unexpected parameter userID, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmVerify.VerifyMock.defaultExpectation.expectationOrigins.originUserID, *mm_want_ptrs.userID, mm_got.userID, minimock.Diff(*mm_want_ptrs.userID, mm_got.userID))
			}

			if mm_want_ptrs.code != nil && !minimock.Equal(*mm_want_ptrs.code, mm_got.code) {
				mmVerify.t.Errorf("TwoFAVerifierMock.Verify got unexpected parameter code, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmVerify.VerifyMock.defaultExpectation.expectationOrigins.originCode, *mm_want_ptrs.code, mm_got.code, minimock.Diff(*mm_want_ptrs.code, mm_got.code))
			}

		} else if mm_want != nil && !minimock.Equal(*mm_want, mm_got) {
			mmVerify.t.Errorf("TwoFAVerifierMock.Verify got unexpected parameters, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
				mmVerify.VerifyMock.defaultExpectation.expectationOrigins.origin, *mm_want, mm_got, minimock.Diff(*mm_want, mm_got))
		}

		mm_results := mmVerify.VerifyMock.defaultExpectation.results
		if mm_results == nil {
			mmVerify.t.Fatal("No results are set for the TwoFAVerifierMock.Verify")
		}
		return (*mm_results).b1, (*mm_results).err
	}
	if mmVerify.funcVerify != nil {
		return mmVerify.funcVerify(ctx, userID, code)
	}
	mmVerify.t.Fatalf("Unexpected call to TwoFAVerifierMock.Verify. %v %v %v", ctx, userID, code)
	return
}

// VerifyAfterCounter returns a count of finished TwoFAVerifierMock.Verify invocations
func (mmVerify *TwoFAVerifierMock) VerifyAfterCounter() uint64 {
	return mm_atomic.LoadUint64(&mmVerify.afterVerifyCounter)
}

// VerifyBeforeCounter returns a count of TwoFAVerifierMock.Verify invocations
func (mmVerify *TwoFAVerifierMock) VerifyBeforeCounter() uint64 {
	return mm_atomic.LoadUint64(&mmVerify.beforeVerifyCounter)
}

// Calls returns a list of arguments used in each call to TwoFAVerifierMock.Verify.
// The list is in the same order as the calls were made (i.e. recent calls have a higher index)
func (mmVerify *mTwoFAVerifierMockVerify) Calls() []*TwoFAVerifierMockVerifyParams {
	mmVerify.mutex.RLock()

	argCopy := make([]*TwoFAVerifierMockVerifyParams, len(mmVerify.callArgs))
	copy(argCopy, mmVerify.callArgs)

	mmVerify.mutex.RUnlock()

	return argCopy
}

// MinimockVerifyDone returns true if the count of the Verify invocations corresponds
// the number of defined expectations
func (m *TwoFAVerifierMock) MinimockVerifyDone() bool {
	if m.VerifyMock.optional {
		// Optional methods provide '0 or more' call count restriction.
		return true
	}

	for _, e := range m.VerifyMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			return false
		}
	}

	return m.VerifyMock.invocationsDone()
}

// MinimockVerifyInspect logs each unmet expectation
func (m *TwoFAVerifierMock) MinimockVerifyInspect() {
	for _, e := range m.VerifyMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			m.t.Errorf("Expected call to TwoFAVerifierMock.Verify at\n%s with params: %#v", e.expectationOrigins.origin, *e.params)
		}
	}

	afterVerifyCounter := mm_atomic.LoadUint64(&m.afterVerifyCounter)
	// if default expectation was set then invocations count should be greater than zero
	if m.VerifyMock.defaultExpectation != nil && afterVerifyCounter < 1 {
		if m.VerifyMock.defaultExpectation.params == nil {
			m.t.Errorf("Expected call to TwoFAVerifierMock.Verify at\n%s", m.VerifyMock.defaultExpectation.returnOrigin)
		} else {
			m.t.Errorf("Expected call to TwoFAVerifierMock.Verify at\n%s with params: %#v", m.VerifyMock.defaultExpectation.expectationOrigins.origin, *m.VerifyMock.defaultExpectation.params)
		}
	}
	// if func was set then invocations count should be greater than zero
	if m.funcVerify != nil && afterVerifyCounter < 1 {
		m.t.Errorf("Expected call to TwoFAVerifierMock.Verify at\n%s", m.funcVerifyOrigin)
	}

	if !m.VerifyMock.invocationsDone() && afterVerifyCounter > 0 {
		m.t.Errorf("Expected %d calls to TwoFAVerifierMock.Verify at\n%s but found %d calls",
			mm_atomic.LoadUint64(&m.VerifyMock.expectedInvocations), m.VerifyMock.expectedInvocationsOrigin, afterVerifyCounter)
	}
}

// MinimockFinish checks that all mocked methods have been called the expected number of times
func (m *TwoFAVerifierMock) MinimockFinish() {
	m.finishOnce.Do(func() {
		if !m.minimockDone() {
			m.MinimockIsEnabledInspect()

			m.MinimockVerifyInspect()
		}
	})
}

// MinimockWait waits for all mocked methods to be called the expected number of times
func (m *TwoFAVerifierMock) MinimockWait(timeout mm_time.Duration) {
	timeoutCh := mm_time.After(timeout)
	for {
		if m.minimockDone() {
			return
		}
		select {
		case <-timeoutCh:
			m.MinimockFinish()
			return
		case <-mm_time.After(10 * mm_time.Millisecond):
		}
	}
}

func (m *TwoFAVerifierMock) minimockDone() bool {
	done := true
	return done &&
		m.MinimockIsEnabledDone() &&
		m.MinimockVerifyDone()
}
